19	/********************************************************************
20	 * - Add a command to Shell environment: generate fabric Verilog
21	 * - Add associated options
22	 * - Add command dependency
23	 *******************************************************************/
24	template <class T>
25	ShellCommandId add_write_fabric_verilog_command_template(
26	  openfpga::Shell<T>& shell, const ShellCommandClassId& cmd_class_id,
27	  const std::vector<ShellCommandId>& dependent_cmds, const bool& hidden) {
28	  Command shell_cmd("write_fabric_verilog");
29	
30	  /* Add an option '--file' in short '-f'*/
31	  CommandOptionId output_opt = shell_cmd.add_option(
32	    "file", true, "Specify the output directory for Verilog netlists");
33	  shell_cmd.set_option_short_name(output_opt, "f");
34	  shell_cmd.set_option_require_value(output_opt, openfpga::OPT_STRING);
35	
36	  /* Add an option '--constant_undriven_inputs' */
37	  CommandOptionId const_undriven_inputs_opt = shell_cmd.add_option(
38	    "constant_undriven_inputs", false,
39	    "Can be [none|bus0|bus1|bit0|bit1]. Use constant vdd/gnd for undriven "
40	    "wires in Verilog netlists. Recommand to "
41	    "enable when there are boundary routing tracks in FPGA fabric");
42	  shell_cmd.set_option_require_value(const_undriven_inputs_opt,
43	                                     openfpga::OPT_STRING);
44	
45	  /* Add an option '--explicit_port_mapping' */
46	  shell_cmd.add_option("explicit_port_mapping", false,
47	                       "Use explicit port mapping in Verilog netlists");
48	
49	  /* Add an option '--include_timing' */
50	  shell_cmd.add_option("include_timing", false,
51	                       "Enable timing annotation in Verilog netlists");
52	
53	  /* Add an option '--print_user_defined_template' */
54	  shell_cmd.add_option(
55	    "print_user_defined_template", false,
56	    "Generate a template Verilog files for user-defined circuit models");
57	
58	  /* Add an option '--default_net_type' */
59	  CommandOptionId default_net_type_opt = shell_cmd.add_option(
60	    "default_net_type", false,
61	    "Set the default net type for Verilog netlists. Default value is 'none'");
62	  shell_cmd.set_option_require_value(default_net_type_opt,
63	                                     openfpga::OPT_STRING);
64	
65	  /* Add an option '--no_time_stamp' */
66	  shell_cmd.add_option("no_time_stamp", false,
67	                       "Do not print a time stamp in the output files");
68	
69	  /* Add an option '--use_relative_path' */
70	  shell_cmd.add_option(
71	    "use_relative_path", false,
72	    "Force to use relative path in netlists when including other netlists");
73	
74	  CommandOptionId le_opt =
75	    shell_cmd.add_option("little_endian", false,
76	                         "Use little endian format in Verilog netlists. By "
77	                         "default, big endian is considered");
78	  shell_cmd.set_option_short_name(le_opt, "le");
79	
80	  /* Add an option '--verbose' */
81	  shell_cmd.add_option("verbose", false, "Enable verbose output");
82	
83	  /* Add command 'write_fabric_verilog' to the Shell */
84	  ShellCommandId shell_cmd_id = shell.add_command(
85	    shell_cmd, "generate Verilog netlists modeling full FPGA fabric", hidden);
86	  shell.set_command_class(shell_cmd_id, cmd_class_id);
87	  shell.set_command_execute_function(shell_cmd_id,
88	                                     write_fabric_verilog_template<T>);
89	
90	  /* Add command dependency to the Shell */
91	  shell.set_command_dependency(shell_cmd_id, dependent_cmds);
92	
93	  return shell_cmd_id;
94	}
