673	template <class T>
674	void add_verilog_command_templates(openfpga::Shell<T>& shell,
675	                                   const bool& hidden = false) {
676	  /* Get the unique id of 'build_fabric' command which is to be used in creating
677	   * the dependency graph */
678	  const ShellCommandId& build_fabric_cmd_id =
679	    shell.command(std::string("build_fabric"));
680	
681	  /* Add a new class of commands */
682	  ShellCommandClassId openfpga_verilog_cmd_class =
683	    shell.add_command_class("FPGA-Verilog");
684	
685	  /********************************
686	   * Command 'write_fabric_verilog'
687	   */
688	  /* The 'write_fabric_verilog' command should NOT be executed before
689	   * 'build_fabric' */
690	  std::vector<ShellCommandId> fabric_verilog_dependent_cmds;
691	  fabric_verilog_dependent_cmds.push_back(build_fabric_cmd_id);
692	  add_write_fabric_verilog_command_template<T>(
693	    shell, openfpga_verilog_cmd_class, fabric_verilog_dependent_cmds, hidden);
694	
695	  /********************************
696	   * Command 'write_full_testbench'
697	   */
698	  /* The command 'write_full_testbench' should NOT be executed before
699	   * 'build_fabric' */
700	  std::vector<ShellCommandId> full_testbench_dependent_cmds;
701	  full_testbench_dependent_cmds.push_back(build_fabric_cmd_id);
702	  add_write_full_testbench_command_template<T>(
703	    shell, openfpga_verilog_cmd_class, full_testbench_dependent_cmds, hidden);
704	
705	  /********************************
706	   * Command 'write_preconfigured_fabric_wrapper'
707	   */
708	  /* The command 'write_preconfigured_fabric_wrapper' should NOT be executed
709	   * before 'build_fabric' */
710	  std::vector<ShellCommandId> preconfig_wrapper_dependent_cmds;
711	  preconfig_wrapper_dependent_cmds.push_back(build_fabric_cmd_id);
712	  add_write_preconfigured_fabric_wrapper_command_template<T>(
713	    shell, openfpga_verilog_cmd_class, preconfig_wrapper_dependent_cmds,
714	    hidden);
715	
716	  /********************************
717	   * Command 'write_testbench_template'
718	   */
