733	  testbench_io_conkt_dependent_cmds.push_back(build_fabric_cmd_id);
734	  add_write_testbench_io_connection_command_template<T>(
735	    shell, openfpga_verilog_cmd_class, testbench_io_conkt_dependent_cmds,
736	    hidden);
737	
738	  /********************************
739	   * Command 'write_mock_fpga_wrapper'
740	   */
