39	/********************************************************************
40	 * Identify the unique GSBs from the Device RR GSB arrays
41	 * This function should only be called after the GSB builder is done
42	 *******************************************************************/
43	template <class T>
44	void compress_routing_hierarchy_template(T& openfpga_ctx,
45	                                         const bool& verbose_output) {
46	  vtr::ScopedStartFinishTimer timer(
47	    "Identify unique General Switch Blocks (GSBs)");
48	
49	  /* Build unique module lists */
50	  RRGraphInEdges in_edges;
51	  in_edges.init(g_vpr_ctx.device().rr_graph);
52	  openfpga_ctx.mutable_device_rr_gsb().build_unique_module(
53	    g_vpr_ctx.device().rr_graph, in_edges);
54	
55	  /* Report the stats */
56	  VTR_LOGV(
57	    verbose_output,
58	    "Detected %lu unique X-direction connection blocks from a total of %d "
59	    "(compression rate=%.2f%)\n",
60	    openfpga_ctx.device_rr_gsb().get_num_cb_unique_module(e_rr_type::CHANX),
61	    find_device_rr_gsb_num_cb_modules(openfpga_ctx.device_rr_gsb(),
62	                                      e_rr_type::CHANX),
63	    100. * ((float)find_device_rr_gsb_num_cb_modules(
64	              openfpga_ctx.device_rr_gsb(), e_rr_type::CHANX) /
65	              (float)openfpga_ctx.device_rr_gsb().get_num_cb_unique_module(
66	                e_rr_type::CHANX) -
67	            1.));
68	
69	  VTR_LOGV(
70	    verbose_output,
71	    "Detected %lu unique Y-direction connection blocks from a total of %d "
72	    "(compression rate=%.2f%)\n",
73	    openfpga_ctx.device_rr_gsb().get_num_cb_unique_module(e_rr_type::CHANY),
74	    find_device_rr_gsb_num_cb_modules(openfpga_ctx.device_rr_gsb(),
75	                                      e_rr_type::CHANY),
76	    100. * ((float)find_device_rr_gsb_num_cb_modules(
77	              openfpga_ctx.device_rr_gsb(), e_rr_type::CHANY) /
78	              (float)openfpga_ctx.device_rr_gsb().get_num_cb_unique_module(
79	                e_rr_type::CHANY) -
80	            1.));
81	
82	  VTR_LOGV(
83	    verbose_output,
84	    "Detected %lu unique switch blocks from a total of %d (compression "
85	    "rate=%.2f%)\n",
86	    openfpga_ctx.device_rr_gsb().get_num_sb_unique_module(),
87	    find_device_rr_gsb_num_sb_modules(openfpga_ctx.device_rr_gsb()),
88	    100. *
89	      ((float)find_device_rr_gsb_num_sb_modules(openfpga_ctx.device_rr_gsb()) /
90	         (float)openfpga_ctx.device_rr_gsb().get_num_sb_unique_module() -
91	       1.));
92	
93	  VTR_LOG(
94	    "Detected %lu unique general switch blocks from a total of %d (compression "
95	    "rate=%.2f%)\n",
96	    openfpga_ctx.device_rr_gsb().get_num_gsb_unique_module(),
97	    find_device_rr_gsb_num_gsb_modules(openfpga_ctx.device_rr_gsb(),
98	                                       g_vpr_ctx.device().rr_graph),
99	    100. * ((float)find_device_rr_gsb_num_gsb_modules(
100	              openfpga_ctx.device_rr_gsb(), g_vpr_ctx.device().rr_graph) /
101	              (float)openfpga_ctx.device_rr_gsb().get_num_gsb_unique_module() -
102	            1.));
103	}
