244	/********************************************************************
245	 * A wrapper function to call the report_arch_bitstream_distribution() in FPGA
246	 *bitstream
247	 *******************************************************************/
248	template <class T>
249	int report_bitstream_distribution_template(const T& openfpga_ctx,
250	                                           const Command& cmd,
251	                                           const CommandContext& cmd_context) {
252	  CommandOptionId opt_file = cmd.option("file");
253	  CommandOptionId opt_no_time_stamp = cmd.option("no_time_stamp");
254	
255	  int status = CMD_EXEC_SUCCESS;
256	
257	  VTR_ASSERT(true == cmd_context.option_enable(cmd, opt_file));
258	
259	  std::string src_dir_path =
260	    find_path_dir_name(cmd_context.option_value(cmd, opt_file));
261	
262	  /* Create directories */
263	  create_directory(src_dir_path, true, true);
264	
265	  /* Default depth requirement, this is to limit the report size by default */
266	  int depth = 1;
267	  CommandOptionId opt_depth = cmd.option("depth");
268	  if (true == cmd_context.option_enable(cmd, opt_depth)) {
269	    depth = std::atoi(cmd_context.option_value(cmd, opt_depth).c_str());
270	    /* Error out if we have negative depth */
271	    if (0 > depth) {
272	      VTR_LOG_ERROR(
